import{_ as e,o as d,c as o,a2 as r}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"Agent Comparison","description":"","frontmatter":{"title":"Agent Comparison"},"headers":[],"relativePath":"research/concepts/tool-systems/agent-comparison.md","filePath":"research/concepts/tool-systems/agent-comparison.md"}'),i={name:"research/concepts/tool-systems/agent-comparison.md"};function n(a,t,s,l,c,h){return d(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="agent-comparison-—-tool-systems-across-coding-agents" tabindex="-1">Agent Comparison — Tool Systems Across Coding Agents <a class="header-anchor" href="#agent-comparison-—-tool-systems-across-coding-agents" aria-label="Permalink to &quot;Agent Comparison — Tool Systems Across Coding Agents&quot;">​</a></h1><p>Cross-agent comparison of tool system architectures, sandboxing, permissions, edit strategies, and capabilities.</p><p>This document surveys 17 coding agents — from minimal single-tool designs to 30+ tool catalogs — analyzing how each structures its tool system, manages permissions, isolates execution, and handles file edits. The goal is to identify which patterns produce the best outcomes and where the industry is converging.</p><hr><h2 id="_1-tool-count-comparison" tabindex="-1">1. Tool Count Comparison <a class="header-anchor" href="#_1-tool-count-comparison" aria-label="Permalink to &quot;1. Tool Count Comparison&quot;">​</a></h2><p>The number of tools an agent exposes to the LLM varies dramatically — from zero (Aider) to 30+ (Junie CLI). More tools provide finer control but risk overwhelming the model&#39;s context and increasing selection errors.</p><table tabindex="0"><thead><tr><th>Agent</th><th>Tool Count</th><th>Notable Tools</th><th>Tool Source</th></tr></thead><tbody><tr><td>Junie CLI</td><td>30+</td><td>Full IDE integration, file ops, terminal, search, refactor, debug</td><td>Static + IDE bridge</td></tr><tr><td>Claude Code</td><td>27</td><td>Read, Write, Edit, MultiEdit, Bash, WebFetch, TodoRead/Write, Notebook, MCP</td><td>Static registry</td></tr><tr><td>Warp</td><td>20+</td><td>File ops, shell, LSP queries, web search, Computer Use, PTY control</td><td>Static + dynamic</td></tr><tr><td>Gemini CLI</td><td>18+</td><td>Shell, file editing, web search, memory read/write, Vertex extensions</td><td>Static + discovery</td></tr><tr><td>OpenCode</td><td>14</td><td>File read/write/edit, bash, LSP diagnostics, glob, grep, fetch, think</td><td>Interface registry</td></tr><tr><td>Droid</td><td>12+</td><td>GitHub Actions repair, PR ops, code search, enterprise integrations</td><td>Platform-native</td></tr><tr><td>Sage-Agent</td><td>10+</td><td>ToolManager dispatch, MCP integration, code analysis, execution</td><td>Manager + MCP</td></tr><tr><td>OpenHands</td><td>9</td><td>bash, str_replace_editor, browser_action, think, finish, delegate</td><td>Action classes</td></tr><tr><td>Ante</td><td>8+</td><td>Rust-native tools, custom MCP SDK, file ops, shell</td><td>MCP SDK</td></tr><tr><td>ForgeCode</td><td>6</td><td>bash, str_replace_editor, view, write, glob, grep</td><td>Static</td></tr><tr><td>Goose</td><td>Dynamic</td><td>All tools sourced from MCP servers — count depends on config</td><td>MCP-native</td></tr><tr><td>Pi (π-coding-agent)</td><td>4</td><td>bash, read, write, web_search</td><td>Extensible core</td></tr><tr><td>TongAgents</td><td>3–4</td><td>Minimal per-agent tool set, shared via multi-agent coordination</td><td>Per-agent static</td></tr><tr><td>Capy</td><td>3–4</td><td>Shell, file editor, browser (inside Ubuntu VM)</td><td>VM-scoped</td></tr><tr><td>mini-SWE-agent</td><td>1</td><td>bash only — all file ops via shell commands</td><td>Single tool</td></tr><tr><td>Aider</td><td>0</td><td>No function calling — uses 6 text-based edit formats instead</td><td>Edit formats</td></tr><tr><td>Codex CLI</td><td>5–6</td><td>Shell (primary), file read, apply patch — sandbox is the tool system</td><td>Shell + sandbox</td></tr></tbody></table><h3 id="analysis" tabindex="-1">Analysis <a class="header-anchor" href="#analysis" aria-label="Permalink to &quot;Analysis&quot;">​</a></h3><p>The data reveals a bimodal distribution: agents cluster around either 4–6 tools (minimalist) or 18–30 tools (comprehensive). The mid-range (8–14) is sparsely populated.</p><p><strong>More tools ≠ better performance.</strong> Mini-SWE-agent with a single bash tool and Aider with zero function-call tools both achieve competitive SWE-bench scores. The critical factor is not tool count but tool design:</p><ul><li><strong>Diminishing returns above ~15 tools</strong>: Models start confusing similar tools (e.g., Write vs. Edit vs. MultiEdit). Claude Code mitigates this with tool search — the model queries available tools rather than holding all 27 in context.</li><li><strong>The &quot;4-tool sweet spot&quot;</strong>: Pi, ForgeCode, and Capy demonstrate that bash + read + write + one extra (search, glob, or browser) covers the vast majority of coding tasks.</li><li><strong>Zero-tool viability</strong>: Aider proves that structured text output can replace function calling entirely, with benchmarks showing edit formats sometimes outperform tool-based approaches.</li></ul><hr><h2 id="_2-architecture-pattern-per-agent" tabindex="-1">2. Architecture Pattern Per Agent <a class="header-anchor" href="#_2-architecture-pattern-per-agent" aria-label="Permalink to &quot;2. Architecture Pattern Per Agent&quot;">​</a></h2><p>Each agent&#39;s tool system reflects a fundamental architectural choice about how tool definitions, dispatch, and execution are organized.</p><table tabindex="0"><thead><tr><th>Agent</th><th>Pattern</th><th>Language</th><th>Key Characteristic</th></tr></thead><tbody><tr><td>Codex CLI</td><td>Router + Registry + Sandbox Pipeline</td><td>Rust</td><td>Enum-level tool type distinction (Shell vs. File)</td></tr><tr><td>Goose</td><td>MCP-Native Federation</td><td>Rust</td><td>Everything is an MCP server — no built-in tools</td></tr><tr><td>OpenHands</td><td>Action/Observation Event Stream</td><td>Python</td><td>Tools are Action subclasses; results are Observations</td></tr><tr><td>OpenCode</td><td>Trait/Interface + Linear Registry</td><td>Go</td><td><code>Tool</code> interface with <code>Run(ctx, params)</code> dispatch</td></tr><tr><td>Claude Code</td><td>Registry + Permission Categories</td><td>TypeScript</td><td>Tool search for large catalogs, category-based gating</td></tr><tr><td>Gemini CLI</td><td>Registry + Dynamic Discovery</td><td>TypeScript</td><td>Static tools + runtime extension discovery</td></tr><tr><td>Aider</td><td>Edit Format Protocol System</td><td>Python</td><td>No tool dispatch — model outputs structured text</td></tr><tr><td>mini-SWE-agent</td><td>Single-Tool Delegation</td><td>Python</td><td>All complexity delegated to bash; agent is thin</td></tr><tr><td>ForgeCode</td><td>Registry + Correction Layer</td><td>Python</td><td>Post-hoc tool-call validation and repair</td></tr><tr><td>Pi</td><td>Minimal Extensible Core</td><td>Python</td><td>4 base tools + plugin architecture</td></tr><tr><td>Ante</td><td>Custom MCP SDK</td><td>Rust</td><td>Native Rust MCP implementation, no wrapper layers</td></tr><tr><td>Warp</td><td>Integrated Tool + PTY Pipeline</td><td>Proprietary</td><td>Terminal-native with PTY capture and LSP integration</td></tr><tr><td>Capy</td><td>Hard Agent-Tool Boundary</td><td>Python</td><td>Tools exist only inside Ubuntu VM; agent has no host access</td></tr><tr><td>Junie CLI</td><td>IDE Bridge + CLI Dual-Mode</td><td>Kotlin</td><td>Same tools accessible from IDE plugin or standalone CLI</td></tr><tr><td>Droid</td><td>Enterprise Platform Tools</td><td>TypeScript</td><td>Tools tightly integrated with GitHub platform APIs</td></tr><tr><td>Sage-Agent</td><td>ToolManager + MCP Bridge</td><td>Python</td><td>Centralized ToolManager class dispatches to MCP or local</td></tr><tr><td>TongAgents</td><td>Per-Agent Minimal Tools</td><td>Python</td><td>Each sub-agent gets only the tools relevant to its role</td></tr></tbody></table><h3 id="pattern-categories" tabindex="-1">Pattern Categories <a class="header-anchor" href="#pattern-categories" aria-label="Permalink to &quot;Pattern Categories&quot;">​</a></h3><p><strong>Registry-based (Claude Code, Gemini CLI, OpenCode, Junie CLI):</strong> Tools are registered at startup in a central catalog. The LLM receives tool schemas and picks which to call. This is the most common pattern because it maps directly to the OpenAI function-calling API.</p><p><strong>Action/Observation (OpenHands):</strong> Tools are modeled as actions in an event stream. The agent emits an Action; the runtime executes it and returns an Observation. This decouples tool definition from execution and enables serialization, replay, and distributed execution.</p><p><strong>MCP-Native (Goose, Ante, Sage-Agent):</strong> Tools are defined by external MCP servers. The agent is a thin orchestrator that discovers and invokes tools over the Model Context Protocol. This maximizes extensibility but introduces network latency and server management complexity.</p><p><strong>Edit Format (Aider):</strong> The model outputs structured text (unified diff, search/replace blocks, whole-file rewrites) rather than making function calls. A parser extracts edits and applies them. This avoids function-calling overhead and works with models that lack tool-use training.</p><p><strong>Shell-Centric (Codex CLI, mini-SWE-agent):</strong> The primary (or only) tool is a shell. All file operations, builds, tests, and searches happen through bash commands. The agent&#39;s value comes from sandbox safety (Codex) or prompt engineering (mini-SWE-agent).</p><hr><h2 id="_3-sandboxing-approach-per-agent" tabindex="-1">3. Sandboxing Approach Per Agent <a class="header-anchor" href="#_3-sandboxing-approach-per-agent" aria-label="Permalink to &quot;3. Sandboxing Approach Per Agent&quot;">​</a></h2><p>Sandboxing determines how much damage a misbehaving tool call can inflict. The spectrum ranges from full VM isolation to no protection at all.</p><table tabindex="0"><thead><tr><th>Agent</th><th>Sandbox Type</th><th>Isolation Level</th><th>Platform Support</th><th>Overhead</th><th>Network Access</th></tr></thead><tbody><tr><td>Codex CLI</td><td>3-layer (bwrap + seccomp + Landlock)</td><td>Very High</td><td>Linux native, macOS/Windows partial</td><td>Low</td><td>Blocked by default</td></tr><tr><td>Capy</td><td>Full Ubuntu VM</td><td>Very High</td><td>Cloud-only</td><td>High</td><td>Controlled</td></tr><tr><td>OpenHands</td><td>Docker container per session</td><td>High</td><td>Any Docker host</td><td>Medium</td><td>Configurable</td></tr><tr><td>Gemini CLI</td><td>Multi-tier (Seatbelt on macOS, Docker optional)</td><td>Medium–High</td><td>macOS native, Linux via Docker</td><td>Low–Medium</td><td>Allowed</td></tr><tr><td>Junie CLI</td><td>JVM sandbox + IDE process isolation</td><td>Medium</td><td>Any JVM platform</td><td>Low</td><td>Allowed</td></tr><tr><td>Droid</td><td>GitHub Actions runner isolation</td><td>Medium</td><td>GitHub-hosted</td><td>Medium</td><td>GitHub scoped</td></tr><tr><td>Claude Code</td><td>None (direct host execution)</td><td>None</td><td>Any</td><td>None</td><td>Full</td></tr><tr><td>OpenCode</td><td>None (direct host execution)</td><td>None</td><td>Any</td><td>None</td><td>Full</td></tr><tr><td>Goose</td><td>None (direct host execution)</td><td>None</td><td>Any</td><td>None</td><td>Full</td></tr><tr><td>Aider</td><td>None (direct host execution)</td><td>None</td><td>Any</td><td>None</td><td>Full</td></tr><tr><td>ForgeCode</td><td>None (direct host execution)</td><td>None</td><td>Any</td><td>None</td><td>Full</td></tr><tr><td>Pi</td><td>None (direct host execution)</td><td>None</td><td>Any</td><td>None</td><td>Full</td></tr><tr><td>Ante</td><td>None (direct host execution)</td><td>None</td><td>Any</td><td>None</td><td>Full</td></tr><tr><td>Warp</td><td>Terminal sandbox (PTY isolation)</td><td>Low</td><td>macOS, Linux</td><td>Low</td><td>Full</td></tr><tr><td>mini-SWE-agent</td><td>External (Docker when used in benchmarks)</td><td>Depends</td><td>Any</td><td>Depends</td><td>Depends</td></tr><tr><td>Sage-Agent</td><td>None (direct host execution)</td><td>None</td><td>Any</td><td>None</td><td>Full</td></tr><tr><td>TongAgents</td><td>None (direct host execution)</td><td>None</td><td>Any</td><td>None</td><td>Full</td></tr></tbody></table><h3 id="the-sandboxing-spectrum" tabindex="-1">The Sandboxing Spectrum <a class="header-anchor" href="#the-sandboxing-spectrum" aria-label="Permalink to &quot;The Sandboxing Spectrum&quot;">​</a></h3><p><strong>Full OS Isolation (Codex CLI):</strong> Codex CLI implements the most sophisticated sandbox in the ecosystem. Three nested layers work together:</p><ol><li><strong>bubblewrap (bwrap):</strong> Linux namespace isolation — the process sees a restricted filesystem, PID space, and network.</li><li><strong>seccomp:</strong> System call filtering — blocks dangerous syscalls like <code>mount</code>, <code>reboot</code>, <code>ptrace</code>.</li><li><strong>Landlock:</strong> Filesystem access control — even within the namespace, only whitelisted paths are writable.</li></ol><p>On macOS, Codex falls back to Apple&#39;s Seatbelt sandbox (the same technology used for App Store apps). The overhead is minimal because all three mechanisms are kernel-level, not virtualization.</p><p><strong>Container Isolation (OpenHands):</strong> Docker provides strong isolation with moderate overhead. Each coding session runs in a fresh container with mounted workspace. The main trade-off is startup time (~2–5 seconds) and the requirement for Docker to be installed.</p><p><strong>VM Isolation (Capy):</strong> The maximum isolation — a full Ubuntu VM means the agent literally cannot affect the host. This is ideal for untrusted code execution but imposes significant overhead (VM boot time, resource allocation, snapshot management).</p><p><strong>No Isolation (most agents):</strong> The majority of agents — including Claude Code, Goose, OpenCode, and Aider — run tools directly on the host with the user&#39;s permissions. They rely on permission prompts (see Section 4) rather than OS-level sandboxing. This is a conscious trade-off: zero overhead and full capability at the cost of trusting the model.</p><hr><h2 id="_4-permission-model-per-agent" tabindex="-1">4. Permission Model Per Agent <a class="header-anchor" href="#_4-permission-model-per-agent" aria-label="Permalink to &quot;4. Permission Model Per Agent&quot;">​</a></h2><p>Permission systems determine when the agent must ask the user before acting. They range from &quot;ask for everything&quot; to &quot;auto-approve all.&quot;</p><table tabindex="0"><thead><tr><th>Agent</th><th>Model Type</th><th>Modes/Levels</th><th>Granularity</th><th>Config Format</th></tr></thead><tbody><tr><td>Claude Code</td><td>5 permission modes</td><td>Suggest, Ask, Auto-edit, Auto-bash, Full auto</td><td>Per-tool-category</td><td>CLI flags + settings</td></tr><tr><td>Junie CLI</td><td>4-level permissions</td><td>Ask all, Ask destructive, Ask external, Trust all</td><td>Per-action-type</td><td>Config file</td></tr><tr><td>Codex CLI</td><td>3 execution policies</td><td>Suggest, Auto-edit, Full auto</td><td>Per-policy</td><td>CLI flag</td></tr><tr><td>Gemini CLI</td><td>3 safety levels</td><td>Conservative, balanced, permissive</td><td>Per-tool-type</td><td>CLI flag + config</td></tr><tr><td>OpenCode</td><td>Allowlist system</td><td>Explicit approval for dangerous commands</td><td>Per-command-pattern</td><td>Config file (regex)</td></tr><tr><td>Goose</td><td>4-tier inspection</td><td>Pre/post inspect, approve, deny</td><td>Per-MCP-server</td><td>MCP config</td></tr><tr><td>OpenHands</td><td>Confirmation prompts</td><td>Confirm destructive actions</td><td>Per-action-class</td><td>Runtime config</td></tr><tr><td>Capy</td><td>VM boundary</td><td>Everything allowed inside VM, nothing outside</td><td>Binary (in/out)</td><td>Architecture</td></tr><tr><td>Warp</td><td>Smart prompting</td><td>Context-aware approval requests</td><td>Per-risk-level</td><td>Adaptive</td></tr><tr><td>Droid</td><td>Enterprise policy</td><td>Organization-level permissions</td><td>Per-repo / per-org</td><td>GitHub settings</td></tr><tr><td>Aider</td><td>User confirmation</td><td>Ask before applying edits, auto-commit optional</td><td>Per-edit-batch</td><td>CLI flags</td></tr><tr><td>ForgeCode</td><td>Minimal</td><td>Trust model by default</td><td>None</td><td>None</td></tr><tr><td>Pi</td><td>Minimal</td><td>Trust model by default</td><td>None</td><td>None</td></tr><tr><td>mini-SWE-agent</td><td>None</td><td>Full trust (sandboxed externally)</td><td>None</td><td>None</td></tr><tr><td>Ante</td><td>MCP-level</td><td>Per-MCP-server permissions</td><td>Per-server</td><td>MCP config</td></tr><tr><td>Sage-Agent</td><td>ToolManager</td><td>Per-tool approval</td><td>Per-tool</td><td>Manager config</td></tr><tr><td>TongAgents</td><td>None</td><td>Agent coordination handles safety</td><td>Per-agent-role</td><td>Multi-agent config</td></tr></tbody></table><h3 id="permission-design-principles" tabindex="-1">Permission Design Principles <a class="header-anchor" href="#permission-design-principles" aria-label="Permalink to &quot;Permission Design Principles&quot;">​</a></h3><p><strong>The Claude Code approach</strong> is the most granular: 5 distinct modes ranging from &quot;suggest only&quot; (never executes anything) to &quot;full auto&quot; (executes everything without asking). Intermediate modes allow auto-editing files but prompting for bash commands, or auto-running whitelisted commands while prompting for others. This maps well to trust escalation — start cautious, increase autonomy as trust builds.</p><p><strong>Codex CLI&#39;s policy engine</strong> is simpler but architecturally elegant. The three policies (suggest, auto-edit, full-auto) are enforced at the sandbox level. In &quot;suggest&quot; mode, the sandbox blocks all writes. In &quot;auto-edit&quot; mode, file writes are allowed but network access remains blocked. In &quot;full-auto&quot; mode, all sandbox restrictions are relaxed. The policy is the sandbox configuration.</p><p><strong>Goose&#39;s 4-tier inspection pipeline</strong> is unique: every tool call passes through pre-inspection (before execution), approval (human or policy), execution, and post-inspection (after execution). Post-inspection is particularly novel — it can detect that a tool call succeeded but produced problematic output (e.g., a file write that introduced a syntax error) and flag it for review.</p><p><strong>Capy&#39;s architectural permission model</strong> is the most radical: there is no permission system because there doesn&#39;t need to be one. The agent runs inside a full VM. It can <code>rm -rf /</code> and the only consequence is the VM gets rebuilt. The sandbox IS the permission system.</p><hr><h2 id="_5-edit-strategy-per-agent" tabindex="-1">5. Edit Strategy Per Agent <a class="header-anchor" href="#_5-edit-strategy-per-agent" aria-label="Permalink to &quot;5. Edit Strategy Per Agent&quot;">​</a></h2><p>How agents modify files is perhaps the most consequential tool design decision. A single wrong edit can break an entire codebase.</p><table tabindex="0"><thead><tr><th>Agent</th><th>Edit Approach</th><th>Error Recovery</th><th>Syntax Awareness</th><th>Multi-file</th></tr></thead><tbody><tr><td>Aider</td><td>6 text-based edit formats</td><td>4-level fuzzy matching</td><td>tree-sitter linting</td><td>Yes (repo map)</td></tr><tr><td>Claude Code</td><td>search-and-replace (old_str/new_str)</td><td>Retry with error msg</td><td>None built-in</td><td>Yes (MultiEdit)</td></tr><tr><td>OpenHands</td><td>str_replace_editor (5 operations)</td><td>Error as Observation</td><td>None built-in</td><td>Sequential</td></tr><tr><td>OpenCode</td><td>Line-range editing</td><td>LSP diagnostics post-edit</td><td>LSP integration</td><td>Sequential</td></tr><tr><td>Gemini CLI</td><td>search-and-replace + full rewrite</td><td>Retry with context</td><td>None built-in</td><td>Yes</td></tr><tr><td>ForgeCode</td><td>str_replace (SWE-bench naming)</td><td>Correction layer</td><td>None built-in</td><td>Sequential</td></tr><tr><td>Codex CLI</td><td>Shell-based (sed, patch, heredoc)</td><td>Sandbox retry</td><td>None built-in</td><td>Shell scripts</td></tr><tr><td>mini-SWE-agent</td><td>Shell-based (sed, ed, tee)</td><td>Model retry</td><td>None built-in</td><td>Shell scripts</td></tr><tr><td>Warp</td><td>Direct file write + LSP validation</td><td>LSP error detection</td><td>LSP</td><td>Yes</td></tr><tr><td>Junie CLI</td><td>IDE-native refactoring + direct edit</td><td>IDE error detection</td><td>Full IDE analysis</td><td>Yes (IDE)</td></tr><tr><td>Pi</td><td>File write (whole file)</td><td>Model retry</td><td>None</td><td>Sequential</td></tr><tr><td>Goose</td><td>MCP server dependent</td><td>Server dependent</td><td>Server dependent</td><td>Server dependent</td></tr><tr><td>Capy</td><td>Shell-based (inside VM)</td><td>VM snapshot rollback</td><td>None</td><td>Shell scripts</td></tr><tr><td>Ante</td><td>MCP-based editing</td><td>MCP server dependent</td><td>None</td><td>Server dependent</td></tr><tr><td>Droid</td><td>GitHub API (PR-based edits)</td><td>PR revision</td><td>GitHub checks</td><td>Yes (PR scope)</td></tr><tr><td>Sage-Agent</td><td>Managed file write</td><td>ToolManager validation</td><td>None</td><td>Sequential</td></tr><tr><td>TongAgents</td><td>Per-agent file ops</td><td>Agent coordination</td><td>None</td><td>Multi-agent</td></tr></tbody></table><h3 id="edit-format-deep-dive-aider-s-6-formats" tabindex="-1">Edit Format Deep Dive: Aider&#39;s 6 Formats <a class="header-anchor" href="#edit-format-deep-dive-aider-s-6-formats" aria-label="Permalink to &quot;Edit Format Deep Dive: Aider&#39;s 6 Formats&quot;">​</a></h3><p>Aider stands alone in offering multiple edit formats, each optimized for different models and tasks:</p><ol><li><strong>Whole file</strong>: Model outputs entire file content. Simple but token-expensive for large files.</li><li><strong>Unified diff</strong>: Standard <code>diff -u</code> format. Token-efficient but models often produce malformed diffs.</li><li><strong>Search/replace</strong>: Blocks of <code>&lt;&lt;&lt;&lt;&lt;&lt;&lt; SEARCH</code> / <code>&gt;&gt;&gt;&gt;&gt;&gt;&gt; REPLACE</code>. The most reliable format.</li><li><strong>Editor diff</strong>: Optimized diff format for editor-trained models.</li><li><strong>Editor whole</strong>: Hybrid of editor diff and whole file.</li><li><strong>Diff-fenced</strong>: Fenced code blocks containing diffs.</li></ol><p>Aider&#39;s key insight: <strong>function calling is worse than text for edits.</strong> Their benchmarks show that text-based edit formats outperform equivalent function-calling approaches because models can use their natural language abilities to describe changes rather than filling structured schemas.</p><h3 id="the-convergence-on-search-and-replace" tabindex="-1">The Convergence on Search-and-Replace <a class="header-anchor" href="#the-convergence-on-search-and-replace" aria-label="Permalink to &quot;The Convergence on Search-and-Replace&quot;">​</a></h3><p>Despite different origins, most agents have converged on some variant of search-and-replace:</p><ul><li><strong>Claude Code</strong>: <code>old_str</code> / <code>new_str</code> parameters</li><li><strong>OpenHands</strong>: <code>str_replace</code> command within editor tool</li><li><strong>ForgeCode</strong>: <code>str_replace_editor</code> (named to match SWE-bench training data)</li><li><strong>Aider</strong>: Search/replace blocks in text output</li><li><strong>Gemini CLI</strong>: Search-and-replace with fallback to full rewrite</li></ul><p>This convergence is driven by a fundamental property: search-and-replace requires the model to reproduce the exact existing code before modifying it, which forces the model to verify its understanding of the current state. Whole-file rewrites don&#39;t have this property and are prone to accidentally deleting code.</p><hr><h2 id="_6-analysis-what-works-best" tabindex="-1">6. Analysis: What Works Best? <a class="header-anchor" href="#_6-analysis-what-works-best" aria-label="Permalink to &quot;6. Analysis: What Works Best?&quot;">​</a></h2><h3 id="trend-1-the-sweet-spot-for-tool-count-is-4–8" tabindex="-1">Trend 1: The &quot;Sweet Spot&quot; for Tool Count Is 4–8 <a class="header-anchor" href="#trend-1-the-sweet-spot-for-tool-count-is-4–8" aria-label="Permalink to &quot;Trend 1: The &quot;Sweet Spot&quot; for Tool Count Is 4–8&quot;">​</a></h3><p>High-performing agents on SWE-bench span the full tool-count range, but the most efficient designs cluster around 4–8 tools. This range provides enough granularity for common operations (read, write, edit, search, execute) without overwhelming the model&#39;s tool selection.</p><p>Agents with 20+ tools (Claude Code, Junie CLI, Warp) compensate with tool search, categorization, or dynamic loading to keep the active tool set small. The effective tool count — what the model actually considers per turn — is usually under 10 even in large-catalog agents.</p><h3 id="trend-2-mcp-adoption-is-accelerating" tabindex="-1">Trend 2: MCP Adoption Is Accelerating <a class="header-anchor" href="#trend-2-mcp-adoption-is-accelerating" aria-label="Permalink to &quot;Trend 2: MCP Adoption Is Accelerating&quot;">​</a></h3><p>The Model Context Protocol is becoming the standard for tool extensibility:</p><ul><li><strong>Goose</strong>: MCP-native — all tools are MCP servers</li><li><strong>Claude Code</strong>: MCP support for external tools alongside built-in catalog</li><li><strong>Ante</strong>: Custom Rust MCP SDK for native performance</li><li><strong>Sage-Agent</strong>: ToolManager bridges local tools and MCP servers</li><li><strong>Gemini CLI</strong>: Extension system compatible with MCP concepts</li></ul><p>MCP&#39;s appeal is composability: an MCP server written for Goose works with Claude Code works with any MCP-compatible agent. This creates a tool ecosystem independent of any single agent.</p><h3 id="trend-3-the-sandboxing-spectrum-has-clear-trade-offs" tabindex="-1">Trend 3: The Sandboxing Spectrum Has Clear Trade-offs <a class="header-anchor" href="#trend-3-the-sandboxing-spectrum-has-clear-trade-offs" aria-label="Permalink to &quot;Trend 3: The Sandboxing Spectrum Has Clear Trade-offs&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Approach</th><th>Safety</th><th>Performance</th><th>Capability</th><th>Complexity</th></tr></thead><tbody><tr><td>Full VM (Capy)</td><td>★★★★★</td><td>★★</td><td>★★★</td><td>★★★★</td></tr><tr><td>OS sandbox (Codex)</td><td>★★★★</td><td>★★★★</td><td>★★★</td><td>★★★★</td></tr><tr><td>Container (OpenHands)</td><td>★★★★</td><td>★★★</td><td>★★★★</td><td>★★★</td></tr><tr><td>App sandbox (Gemini)</td><td>★★★</td><td>★★★★</td><td>★★★★</td><td>★★</td></tr><tr><td>None + permissions</td><td>★★</td><td>★★★★★</td><td>★★★★★</td><td>★</td></tr></tbody></table><p>Most agents choose &quot;none + permissions&quot; because the development experience is frictionless. Codex CLI&#39;s achievement is showing that OS-level sandboxing can be nearly zero-overhead while providing real isolation.</p><h3 id="trend-4-permission-systems-are-shifting-toward-configurable-autonomy" tabindex="-1">Trend 4: Permission Systems Are Shifting Toward Configurable Autonomy <a class="header-anchor" href="#trend-4-permission-systems-are-shifting-toward-configurable-autonomy" aria-label="Permalink to &quot;Trend 4: Permission Systems Are Shifting Toward Configurable Autonomy&quot;">​</a></h3><p>Early agents were binary: ask everything or trust everything. Modern agents offer graduated autonomy:</p><ul><li>Start in &quot;ask&quot; mode for new users</li><li>Allow per-command or per-tool-type exceptions</li><li>Support &quot;full auto&quot; for CI/CD and batch operations</li><li>Provide session-level trust escalation</li></ul><p>This mirrors the Unix permission model&#39;s evolution from simple user/group/other to ACLs and capabilities.</p><h3 id="trend-5-edit-tools-are-converging-on-search-and-replace" tabindex="-1">Trend 5: Edit Tools Are Converging on Search-and-Replace <a class="header-anchor" href="#trend-5-edit-tools-are-converging-on-search-and-replace" aria-label="Permalink to &quot;Trend 5: Edit Tools Are Converging on Search-and-Replace&quot;">​</a></h3><p>The industry has largely settled on search-and-replace as the primary edit mechanism because it:</p><ol><li>Forces the model to demonstrate understanding of existing code</li><li>Supports surgical edits without rewriting entire files</li><li>Is naturally idempotent (same search-and-replace applied twice fails gracefully)</li><li>Maps well to <code>git diff</code> for change review</li></ol><p>Aider&#39;s text-based approach remains a credible alternative, particularly for models without strong function-calling training. The Aider team&#39;s data showing function calling underperforms text editing is the most counterintuitive finding in the space.</p><hr><h2 id="_7-key-differentiators-table" tabindex="-1">7. Key Differentiators Table <a class="header-anchor" href="#_7-key-differentiators-table" aria-label="Permalink to &quot;7. Key Differentiators Table&quot;">​</a></h2><p>For each agent, the single most distinctive aspect of its tool system:</p><table tabindex="0"><thead><tr><th>Agent</th><th>Key Differentiator</th><th>Why It Matters</th></tr></thead><tbody><tr><td>Codex CLI</td><td>3-layer OS sandbox with shell command parser</td><td>Only agent with kernel-level tool isolation at near-zero overhead</td></tr><tr><td>Goose</td><td>MCP-native: everything is an MCP server</td><td>Proves MCP can be the sole tool abstraction, not just an add-on</td></tr><tr><td>Aider</td><td>Function calling is WORSE than text editing</td><td>Challenges the industry assumption that structured tool calls are superior</td></tr><tr><td>ForgeCode</td><td>Tool-call correction layer</td><td>Catches and repairs malformed tool calls before execution</td></tr><tr><td>OpenHands</td><td>Action/observation event stream</td><td>Enables replay, distributed execution, and trajectory analysis</td></tr><tr><td>Claude Code</td><td>Tool search for 27-tool catalog</td><td>Solves tool overflow by letting the model query available tools</td></tr><tr><td>Gemini CLI</td><td>Multi-tier sandboxing with platform adaptation</td><td>Seatbelt on macOS, Docker on Linux — native feel on each OS</td></tr><tr><td>mini-SWE-agent</td><td>Competitive with ONE tool (bash only)</td><td>Proves agent complexity is often unnecessary overhead</td></tr><tr><td>OpenCode</td><td>LSP integration for edit validation</td><td>Post-edit diagnostics catch errors other agents miss</td></tr><tr><td>Warp</td><td>Active AI error monitoring with PTY capture</td><td>Terminal-native intelligence — errors detected as they appear</td></tr><tr><td>Capy</td><td>Hard agent-tool boundary via full VM</td><td>Most extreme isolation — the VM IS the permission system</td></tr><tr><td>Junie CLI</td><td>IDE + CLI dual-mode with shared tools</td><td>Same tool system works in IntelliJ plugin and standalone CLI</td></tr><tr><td>Pi</td><td>4 extensible tools covering full workflow</td><td>Minimal viable tool set that&#39;s still production-capable</td></tr><tr><td>Ante</td><td>Custom Rust MCP SDK</td><td>Native MCP without wrapper overhead — MCP at systems-language speed</td></tr><tr><td>Droid</td><td>GitHub Actions repair and enterprise integration</td><td>Only agent purpose-built for CI/CD pipeline debugging</td></tr><tr><td>Sage-Agent</td><td>ToolManager with MCP bridge</td><td>Clean abstraction layer between local tools and MCP ecosystem</td></tr><tr><td>TongAgents</td><td>Per-agent minimal tools with multi-agent coordination</td><td>Tool minimalism per agent compensated by agent-level composition</td></tr></tbody></table><hr><h2 id="_8-cross-cutting-comparison-matrix" tabindex="-1">8. Cross-Cutting Comparison Matrix <a class="header-anchor" href="#_8-cross-cutting-comparison-matrix" aria-label="Permalink to &quot;8. Cross-Cutting Comparison Matrix&quot;">​</a></h2><p>A consolidated view across all dimensions for quick reference:</p><table tabindex="0"><thead><tr><th>Agent</th><th>Tools</th><th>Sandbox</th><th>Permissions</th><th>Edit Strategy</th><th>Language</th><th>MCP</th></tr></thead><tbody><tr><td>Codex CLI</td><td>5–6</td><td>3-layer OS</td><td>3 policies</td><td>Shell-based</td><td>Rust</td><td>No</td></tr><tr><td>Goose</td><td>Dynamic</td><td>None</td><td>4-tier inspect</td><td>MCP-dependent</td><td>Rust</td><td>Native</td></tr><tr><td>OpenHands</td><td>9</td><td>Docker</td><td>Confirmation</td><td>str_replace</td><td>Python</td><td>No</td></tr><tr><td>OpenCode</td><td>14</td><td>None</td><td>Allowlist</td><td>Line-range</td><td>Go</td><td>No</td></tr><tr><td>Claude Code</td><td>27</td><td>None</td><td>5 modes</td><td>search-replace</td><td>TypeScript</td><td>Yes</td></tr><tr><td>Gemini CLI</td><td>18+</td><td>Multi-tier</td><td>3 levels</td><td>search-replace</td><td>TypeScript</td><td>Partial</td></tr><tr><td>mini-SWE-agent</td><td>1</td><td>External</td><td>None</td><td>Shell-based</td><td>Python</td><td>No</td></tr><tr><td>Aider</td><td>0</td><td>None</td><td>Confirm edits</td><td>6 text formats</td><td>Python</td><td>No</td></tr><tr><td>ForgeCode</td><td>6</td><td>None</td><td>Minimal</td><td>str_replace</td><td>Python</td><td>No</td></tr><tr><td>Pi</td><td>4</td><td>None</td><td>Minimal</td><td>File write</td><td>Python</td><td>No</td></tr><tr><td>Ante</td><td>8+</td><td>None</td><td>MCP-level</td><td>MCP-based</td><td>Rust</td><td>Native</td></tr><tr><td>Warp</td><td>20+</td><td>PTY</td><td>Smart prompts</td><td>Direct + LSP</td><td>Proprietary</td><td>No</td></tr><tr><td>Capy</td><td>3–4</td><td>Full VM</td><td>VM boundary</td><td>Shell-based</td><td>Python</td><td>No</td></tr><tr><td>Junie CLI</td><td>30+</td><td>JVM</td><td>4 levels</td><td>IDE-native</td><td>Kotlin</td><td>No</td></tr><tr><td>Droid</td><td>12+</td><td>Actions runner</td><td>Enterprise</td><td>PR-based</td><td>TypeScript</td><td>No</td></tr><tr><td>Sage-Agent</td><td>10+</td><td>None</td><td>Per-tool</td><td>Managed write</td><td>Python</td><td>Bridge</td></tr><tr><td>TongAgents</td><td>3–4</td><td>None</td><td>None</td><td>Per-agent</td><td>Python</td><td>No</td></tr></tbody></table><hr><h2 id="_9-conclusions" tabindex="-1">9. Conclusions <a class="header-anchor" href="#_9-conclusions" aria-label="Permalink to &quot;9. Conclusions&quot;">​</a></h2><p><strong>There is no single best tool system design.</strong> The optimal architecture depends on the deployment context:</p><ul><li><strong>For maximum safety</strong> (enterprise, untrusted code): Codex CLI&#39;s OS sandbox or Capy&#39;s VM isolation</li><li><strong>For maximum extensibility</strong> (diverse workflows): Goose&#39;s MCP-native approach</li><li><strong>For maximum simplicity</strong> (quick setup, solo dev): mini-SWE-agent or Pi&#39;s minimal tools</li><li><strong>For maximum edit quality</strong> (code modification focus): Aider&#39;s text formats or OpenCode&#39;s LSP validation</li><li><strong>For maximum integration</strong> (IDE users): Junie CLI&#39;s dual-mode architecture</li><li><strong>For maximum autonomy</strong> (CI/CD, batch): Claude Code&#39;s full-auto mode with 27 tools</li></ul><p>The industry is converging on three key patterns:</p><ol><li><strong>Search-and-replace as the primary edit mechanism</strong> — adopted by 10+ of the 17 agents surveyed</li><li><strong>MCP as the extensibility standard</strong> — 6 of 17 agents have some MCP support, and growing</li><li><strong>Graduated permission systems</strong> — binary ask/trust is being replaced by multi-level autonomy</li></ol><p>The most surprising finding remains Aider&#39;s: for file editing, structured text output can outperform function calling. This challenges the assumption that tool-use APIs are always superior and suggests the optimal tool system might use function calling for execution (bash, search) but text protocols for code modification.</p>',88)])])}const u=e(i,[["render",n]]);export{g as __pageData,u as default};
